import{_ as n,o as t,c as s,a,b as e,e as i}from"./app-76996780.js";const l={},o=a("p",null,"集成算法（Ensemble）的思路是训练多个模型，当需要预测一个新样本时，使用这些模型分别对这个样本预测，若是分类问题，采用投票法决定最后的类别预测；若是回归问题，取均值。",-1),p=a("h2",{id:"bagging",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#bagging","aria-hidden":"true"},"#"),e(" Bagging")],-1),r=a("p",null,[e("Bagging是Bootstrap Aggregating的缩写。核心思想是：采用有放回的采样规则，从m个样本的数据集进行n次采样（n "),a("span",{class:"katex"},[a("span",{class:"katex-mathml"},[a("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[a("semantics",null,[a("mrow",null,[a("mo",null,"≤")]),a("annotation",{encoding:"application/x-tex"},"\\leq")])])]),a("span",{class:"katex-html","aria-hidden":"true"},[a("span",{class:"base"},[a("span",{class:"strut",style:{height:"0.7719em","vertical-align":"-0.136em"}}),a("span",{class:"mrel"},"≤")])])]),e("m），构成一个包含n个样本的新训练数据集来训练模型，上次过程进行B次，得到B个模型。对一个新样本，使用这些模型分别对这个样本预测，若是分类问题，采用投票法决定最后的类别预测；若是回归问题，取均值。")],-1),g=i('<h2 id="boosting" tabindex="-1"><a class="header-anchor" href="#boosting" aria-hidden="true">#</a> Boosting</h2><p>算法原理是：初始时，有m个样本，给每个样本分配一个初始权重，然后使用这个带权重的数据集训练模型，训练完成后，<strong>增加预测错误的样本的权重值</strong>，然后拿出这个新的带权重的数据集来<strong>训练一个新模型</strong>，重复B次，得到B个模型。</p><p>和Bagging的不同：</p><ul><li><p>采样规则不同，Bagging采用有放回的采样，而boosting采用增加预测错误样本的权重的方法，相当于加强对错误预测的样本的学习力度，从而提高模型的准确性。</p></li><li><p>Bagging算法可以并行训练多个模型，但是Boosting只能串行训练，因为下一个模型依赖于上一个模型的预测结果。</p></li></ul><h2 id="随机森林" tabindex="-1"><a class="header-anchor" href="#随机森林" aria-hidden="true">#</a> 随机森林</h2><p>随机森林每次训练时，随机选择一个特征的子集来训练，该算法有两个参数：决策树的个数、构建单棵决策树特征的个数。</p><p>假设数据集有m个样本，n个特征。</p><p>单颗决策树构建：</p><ul><li><p>有放回采样，从原始数据集经过m采样，得到一个包含m个样本的数据集</p></li><li><p>从n个特征里，使用无放回采样，从中取出f个特征作为输入特征</p></li><li><p>在新数据集上（m个样本，f个特征）构建决策树</p></li><li><p>重复上次过程t次，构造t棵决策树</p></li></ul><p>综合多颗决策树的预测结果作为随机森林的预测结果。若是分类问题，采用投票法决定最后的类别预测；若是回归问题，取均值。</p><p><strong>为什么随机森林要选取特征的子集来构建决策树？</strong></p><p>假如某个输入特征对预测结果是强关联的，这个特征都会在所有决策树里体现，会造成所有的决策树都强烈地反映这个特征的，无法很好的解决过拟合的问题。这和使用正则项是一样的道理，使用正则项的目的是为了让每个特征都参与进来，而不是某一个特征起决定性作用，从而避免过拟合的问题。</p>',12),c=[o,p,r,g];function h(d,m){return t(),s("div",null,c)}const u=n(l,[["render",h],["__file","ensemble.html.vue"]]);export{u as default};
